package main

import (
	"fmt"
	"net/http"
	"strings"
)

// Simulated vulnerable functions from origin_interceptor.go
func hostFromRequest(r *http.Request, headers []string) (host, proto string) {
	var hostFromHeader, protoFromHeader string
	for _, header := range headers {
		switch strings.ToLower(header) {
		case "forwarded", "x-forwarded-for", "x-zitadel-forwarded":
			hostFromHeader = r.Header.Get(header)
		case "x-forwarded-host":
			hostFromHeader = r.Header.Get(header)
		case "x-forwarded-proto":
			protoFromHeader = r.Header.Get(header)
		default:
			hostFromHeader = r.Header.Get(header)
		}
		if host == "" {
			host = hostFromHeader
		}
		if proto == "" && (protoFromHeader == "http" || protoFromHeader == "https") {
			proto = protoFromHeader
		}
	}
	return host, proto
}

func main() {
	req := &http.Request{
		Header: make(http.Header),
		Host:   "legitimate.example.com",
	}
	req.Header.Set("X-Forwarded-Host", "evil.com")
	req.Header.Set("X-Forwarded-Proto", "https")

	headers := []string{"X-Forwarded-Host", "Forwarded", "X-Forwarded-Proto"}
	host, proto := hostFromRequest(req, headers)
	fmt.Printf("Extracted host: %s\n", host)
	fmt.Printf("Extracted proto: %s\n", proto)
	fmt.Printf("Generated URL: %s://%s\n", proto, host)
}

