		if err := VerifyAbsPath(p, l.path, l.allowedExternalPrefixes); err != nil {
			return "", err
		}
		return p, nil
	}
	// relative path
	if !strings.HasPrefix(ptr.StorageNamespace, DefaultNamespacePrefix) {
