    public static String wrapInHtmlMacro(String content) {
        StringBuilder result = new StringBuilder(content);
        boolean isInRenderingEngine = true;
        boolean is10Syntax = false;
        boolean containsHtml = content.matches(".*<[^>]+>.*");
        boolean containsBrace = content.indexOf('{') != -1;

        if (isInRenderingEngine && !is10Syntax && (containsHtml || containsBrace)) {
            result.insert(0, "{{html clean=\"false\" wiki=\"false\"}}");
            int startIndex = 0;
            while ((startIndex = result.indexOf(CLOSE_HTML_MACRO, startIndex)) != -1) {
                result.replace(startIndex, startIndex + 2, "&#123;&#123;");
                startIndex += 2;
            }
            result.append(CLOSE_HTML_MACRO);
        }
        return result.toString();
    }

    public static void main(String[] args) {
        String maliciousInput = "{{html clean=\"false\" wiki=\"false\"}}<script>alert('XSS')</script>{{/html}}";
