// PostgreSQL connector SQL injection vulnerability test for contains operator
// This simulates the vulnerable code path

class ParameterizedSQL {
  constructor(sql, params) {
    this.sql = sql || '';
    this.params = params || [];
  }

  merge(other) {
    if (typeof other === 'string') {
      this.sql += other;
    } else if (other instanceof ParameterizedSQL) {
      this.sql += other.sql;
      this.params = this.params.concat(other.params);
    } else if (other && typeof other === 'object') {
      this.sql += other.sql || '';
      this.params = this.params.concat(other.params || []);
    }
    return this;
  }
}

